function trappingRainWater(data) {
    const heights = data.split(' ').map(Number);
    let n = heights.length;
    if (n === 0) return 0;
    let totalWater = 0;
    for (let i = 0; i < n; i++) {
        let leftMax = 0;
        let rightMax = 0;
        for (let j = 0; j <= i; j++) {
            leftMax = Math.max(leftMax, heights[j]);
        }
        for (let j = i; j < n; j++) {
            rightMax = Math.max(rightMax, heights[j]);
        }
        totalWater += Math.min(leftMax, rightMax) - heights[i];
    }
    return totalWater;
}

