    left[0] = height[0]; for (int i = 1; i < n; i++) left[i] = (height[i] > left[i-1]) ? height[i] : left[i-1];
    right[n-1] = height[n-1]; for (int i = n-2; i >= 0; i--) right[i] = (height[i] > right[i+1]) ? height[i] : right[i+1];
    int sum = 0;
    for (int i = 0; i < n; i++) sum += (left[i] < right[i] ? left[i] : right[i]) - height[i];
    free(left); free(right); return sum;
}

